/**
 * Sopwith WASM platform driver
 *
 * Loads the asset pack extracted by hexlab and the engine_core WASM module,
 * registers the lookup tables, then runs the game loop on requestAnimationFrame.
 *
 * File layout expected (served from same directory as index.html):
 *   engine_core.wasm          — compiled Rust engine
 *   engine_core.js            — wasm-bindgen JS glue (generated by build)
 *   assets_pack.bin           — raw binary asset pack (copy from artifacts/)
 *   assets_pack.json          — manifest produced by hexlab
 */

// ---------------------------------------------------------------------------
// Configuration
// ---------------------------------------------------------------------------

const ASSET_PACK_BIN  = 'assets_pack.bin';
const ASSET_PACK_JSON = 'assets_pack.json';
const WASM_MODULE     = 'engine_core.wasm';
const WASM_JS_GLUE    = './engine_core.js';

// CGA-inspired palette (focus on black / cyan / magenta / white like Sopwith).
const CGA = {
  black:   '#000000',
  cyan:    '#55FFFF',
  magenta: '#FF55FF',
  white:   '#FFFFFF',
  gray:    '#AAAAAA',
  blue:    '#0000AA',
};

// Scale factors
const CANVAS_W = 320;
const CANVAS_H = 200;

// ---------------------------------------------------------------------------
// DOM references
// ---------------------------------------------------------------------------
const canvas = document.getElementById('c');
const ctx    = canvas.getContext('2d');
const hud    = document.getElementById('hud');
const status = document.getElementById('status');

// ---------------------------------------------------------------------------
// Input state
// ---------------------------------------------------------------------------
let inputFlags = 0;

/**
 * inputFlags bitmask:
 *   bit 0 = left
 *   bit 1 = right
 *   bit 2 = up
 *   bit 3 = down
 *   bit 4 = fire pellet (space / z)
 *   bit 5 = bomb (b)
 *   bit 6 = barrel roll (x)
 */
window.addEventListener('keydown', e => {
  const k = e.key.toLowerCase();
  if (k === 'arrowleft'  || k === 'a') inputFlags |=  0b0000001;
  if (k === 'arrowright' || k === 'd') inputFlags |=  0b0000010;
  if (k === 'arrowup'    || k === 'w') inputFlags |=  0b0000100;
  if (k === 'arrowdown'  || k === 's') inputFlags |=  0b0001000;
  if (k === ' '          || k === 'z') inputFlags |=  0b0010000;
  if (k === 'b')                       inputFlags |=  0b0100000;
  if (k === 'x')                       inputFlags |=  0b1000000;
  if (["arrowleft", "arrowright", "arrowup", "arrowdown", " "].includes(k)) e.preventDefault();
});
window.addEventListener('keyup', e => {
  const k = e.key.toLowerCase();
  if (k === 'arrowleft'  || k === 'a') inputFlags &= ~0b0000001;
  if (k === 'arrowright' || k === 'd') inputFlags &= ~0b0000010;
  if (k === 'arrowup'    || k === 'w') inputFlags &= ~0b0000100;
  if (k === 'arrowdown'  || k === 's') inputFlags &= ~0b0001000;
  if (k === ' '          || k === 'z') inputFlags &= ~0b0010000;
  if (k === 'b')                       inputFlags &= ~0b0100000;
  if (k === 'x')                       inputFlags &= ~0b1000000;
});

// ---------------------------------------------------------------------------
// Asset helpers
// ---------------------------------------------------------------------------

/**
 * Build a lookup: table_id → { byte_offset, byte_length }
 * from the hexlab manifest.
 *
 * The manifest `name` field follows the pattern "table_001", "table_002", …
 * We map name suffix → table_id integer.
 */
function buildTableIndex(manifest) {
  const index = {};
  if (!manifest || !manifest.entries) return index;
  for (const entry of manifest.entries) {
    const entryType = entry.asset_type || entry.type;
    if (entryType !== 'table') continue;
    let id = Number(entry.id);
    if (!Number.isFinite(id)) {
      const m = String(entry.name || '').match(/table_(\d+)/i);
      if (!m) continue;
      id = parseInt(m[1], 10);
    }
    index[id] = { byte_offset: entry.byte_offset, byte_length: entry.byte_length };
  }
  return index;
}

// ---------------------------------------------------------------------------
// Rendering
// ---------------------------------------------------------------------------

/**
 * Render one frame using data queried directly from the WASM engine.
 *
 * Renders a CGA-styled Sopwith-like scene with extracted terrain tables
 * plus dynamic objects/projectiles from the WASM simulation.
 */
function render(wasm) {
  // Clear to CGA black sky
  ctx.fillStyle = CGA.black;
  ctx.fillRect(0, 0, CANVAS_W, CANVAS_H);

  // Mountain ridge / far terrain silhouette
  ctx.fillStyle = CGA.gray;
  ctx.beginPath();
  ctx.moveTo(0, CANVAS_H);
  for (let x = 0; x < CANVAS_W; x++) {
    const y = wasm.terrain_y_at(x) - 26 + Math.sin((x + wasm.scroll_x()) * 0.05) * 4;
    ctx.lineTo(x, y);
  }
  ctx.lineTo(CANVAS_W, CANVAS_H);
  ctx.closePath();
  ctx.fill();

  // Foreground terrain (playable surface)
  ctx.fillStyle = CGA.white;
  ctx.beginPath();
  ctx.moveTo(0, CANVAS_H);
  for (let x = 0; x < CANVAS_W; x++) {
    const y = wasm.terrain_y_at(x);
    ctx.lineTo(x, y);
  }
  ctx.lineTo(CANVAS_W, CANVAS_H);
  ctx.closePath();
  ctx.fill();

  // Terrain crest accent
  ctx.strokeStyle = CGA.cyan;
  ctx.beginPath();
  for (let x = 0; x < CANVAS_W; x++) {
    const y = wasm.terrain_y_at(x) - 1;
    if (x === 0) ctx.moveTo(x, y);
    else ctx.lineTo(x, y);
  }
  ctx.stroke();

  // Ground objects (cows, tanks, buildings)
  const targetCount = typeof wasm.target_count === 'function' ? wasm.target_count() : 0;
  for (let i = 0; i < targetCount; i++) {
    const tx = wasm.target_x(i);
    const ty = wasm.target_y(i);
    const kind = wasm.target_kind(i);
    if (tx < -20 || tx > CANVAS_W + 20) continue;

    if (kind === 0) {
      // cow
      ctx.fillStyle = CGA.magenta;
      ctx.fillRect(tx - 3, ty - 2, 8, 4);
      ctx.fillStyle = CGA.cyan;
      ctx.fillRect(tx + 4, ty - 1, 3, 2);
    } else if (kind === 1) {
      // tank
      ctx.fillStyle = CGA.cyan;
      ctx.fillRect(tx - 4, ty - 2, 10, 4);
      ctx.fillStyle = CGA.magenta;
      ctx.fillRect(tx - 1, ty - 4, 4, 2);
      ctx.fillRect(tx + 3, ty - 4, 3, 1);
    } else {
      // building
      ctx.fillStyle = CGA.magenta;
      ctx.fillRect(tx - 5, ty - 8, 10, 8);
      ctx.fillStyle = CGA.cyan;
      ctx.fillRect(tx - 3, ty - 6, 6, 6);
    }
  }

  // Active bullets and bombs
  const projectileCount = typeof wasm.projectile_count === 'function' ? wasm.projectile_count() : 0;
  for (let i = 0; i < projectileCount; i++) {
    const px = wasm.projectile_x(i);
    const py = wasm.projectile_y(i);
    const kind = wasm.projectile_kind(i);
    if (px < 0 || px >= CANVAS_W || py < 0 || py >= CANVAS_H) continue;
    if (kind === 0) {
      ctx.fillStyle = CGA.cyan;
      ctx.fillRect(px, py, 2, 1);
    } else {
      ctx.fillStyle = CGA.magenta;
      ctx.fillRect(px - 1, py - 1, 3, 3);
    }
  }

  // Plane (simple triangle representing fuselage)
  const px = wasm.plane_x();
  const py = wasm.plane_y();
  const angle = wasm.plane_angle();

  ctx.save();
  ctx.translate(px, py);

  // Rotate: map 0–511 angle index to radians.
  const rad = (angle / 512) * Math.PI * 2;
  ctx.rotate(rad);

  if (typeof wasm.rolling === 'function' && wasm.rolling()) {
    const pulse = ((wasm.frame_count() >> 1) & 1) === 0;
    ctx.strokeStyle = pulse ? CGA.cyan : CGA.magenta;
    ctx.strokeRect(-8, -8, 16, 16);
  }

  ctx.fillStyle = CGA.cyan;
  ctx.beginPath();
  ctx.moveTo( 8,  0);
  ctx.lineTo(-5,  4);
  ctx.lineTo(-3,  0);
  ctx.lineTo(-5, -4);
  ctx.closePath();
  ctx.fill();

  // Wings and rudder highlights
  ctx.fillStyle = CGA.magenta;
  ctx.fillRect(-2, -7, 4, 14);
  ctx.fillRect(-6, -1, 3, 2);

  ctx.restore();

  // HUD overlay
  const score = typeof wasm.score === 'function' ? wasm.score() : 0;
  hud.textContent =
    `frame ${wasm.frame_count()} | scroll ${wasm.scroll_x()} | ` +
    `x=${px.toFixed(1)} y=${py.toFixed(1)} angle=${angle} ` +
    `| score=${score} targets=${targetCount}`;
}

// ---------------------------------------------------------------------------
// Entry point
// ---------------------------------------------------------------------------

async function main() {
  status.textContent = 'Fetching asset pack…';

  // Load asset manifest
  let manifest = null;
  try {
    const resp = await fetch(ASSET_PACK_JSON);
    if (resp.ok) manifest = await resp.json();
  } catch (_) { /* manifest is optional for this preview */ }

  // Load asset pack bytes
  let packBytes = new Uint8Array(0);
  try {
    const resp = await fetch(ASSET_PACK_BIN);
    if (resp.ok) packBytes = new Uint8Array(await resp.arrayBuffer());
  } catch (_) { /* continue without pack */ }

  // --- Load WASM ----------------------------------------------------------
  // Try to use auto-generated wasm-bindgen glue if present; fall back to
  // manual WebAssembly.instantiateStreaming.
  let wasm;
  try {
    // wasm-bindgen generated glue (available after `wasm-pack build`)
    const mod = await import(WASM_JS_GLUE);
    await mod.default();          // initialises the WASM module
    wasm = mod.glueExports;
  } catch (_) {
    // Manual instantiation (no wasm-bindgen glue yet — build first)
    status.textContent = 'engine_core.js not found — run: cargo build --target wasm32-unknown-unknown';
    console.error('WASM glue not found. See README for build instructions.');
    return;
  }

  // --- Initialise engine ---------------------------------------------------
  wasm.init();

  if (packBytes.length > 0) {
    // Write pack bytes into WASM linear memory, then commit.
    const ptr = wasm.alloc_buf(packBytes.length);
    new Uint8Array(wasm.memory.buffer).set(packBytes, ptr);
    wasm.commit_pack(packBytes.length);
    status.textContent = `Asset pack loaded (${packBytes.length} bytes)`;
  } else {
    status.textContent = 'No asset pack found — terrain will be flat.';
  }

  // Register lookup tables using manifest offsets
  if (manifest) {
    const tableIndex = buildTableIndex(manifest);
    for (const [id, loc] of Object.entries(tableIndex)) {
      wasm.register_table(Number(id), loc.byte_offset, loc.byte_length);
    }
    status.textContent += ` | ${Object.keys(tableIndex).length} tables registered`;
  }

  // --- Game loop -----------------------------------------------------------
  function loop() {
    wasm.tick(inputFlags);
    render(wasm);
    requestAnimationFrame(loop);
  }

  requestAnimationFrame(loop);
}

main().catch(err => {
  status.textContent = `Error: ${err.message}`;
  console.error(err);
});
